<?php
declare(strict_types=1);namespace App\DTO\ControlEscaneres;final readonly class SchemaInspectionResult{/** @param list<SchemaCheck> $checks */public function __construct(public string$state,public array$checks,public array$missingTables,public array$missingCriticalColumns,public array$missingRecommendedIndexes){if(!in_array($state,['absent','canonical_complete','canonical_partial','legacy_incompatible','unknown'],true))throw new \InvalidArgumentException('Estado de esquema inválido.');}public function exitCode():int{foreach($this->checks as$c)if($c->status==='BLOCKED')return 2;foreach($this->checks as$c)if($c->status==='WARN')return 1;return 0;}}
